27	    }
28	    const countsByType: Record<string, number> = {};
29	    for (const item of items) {
30	      countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
31	    }
32	    let basePremium = 0;
33	    for (const [type, count] of Object.entries(countsByType)) {
34	      if ((type === "rune" || type === "moonstone") && count === 3) {
35	        basePremium += 60;
36	      } else {
37	        basePremium += count * BASE_PREMIUM_BY_TYPE[type];
38	      }
39	    }
40	    let itemSurcharges = 0;
41	    for (const item of items) {
42	      if (item.cursed) {
43	        itemSurcharges += BASE_PREMIUM_BY_TYPE[item.type] * 0.5;
44	      }
45	      if (item.enchantment >= 5) {
46	        itemSurcharges += BASE_PREMIUM_BY_TYPE[item.type] * 0.3;
47	      }
48	    }
49	    const loyaltyDiscount = input.customer.yearsWithMHPCO >= 2 ? basePremium * 0.2 : 0;
50	    const followUpDiscount = quoteCount > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
51	    const premium = Math.ceil(basePremium + itemSurcharges + basePremium * FIRST_INSURANCE_RATE - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
52	    results.push({ premium });
53	    quoteCount++;
54	  }
55	  return { results };
56	}
